<template>
    <b-modal id="modalOrder" v-model="modalShow" hide-footer hide-header>
        <div class="modal-dialog" role="document">
            <div class="modal-content">
                <div class="modal-body modal-form">
                    <form action="">
                        <p class="modal-form__title">Добавлено в заказ:</p>
                        <p class="modal-form__name-model">{{productInfo.name}}</p>
                        <div class="form-options color" v-if="(items.length > 0)">
                            <p>цвет</p>
                            <p>кол-во</p>
                            <div class="form-options__item" v-for="item in items" :key="item.offerId">
                                <input disabled type="text" class="form-options__color" :value="item.colorTitle">
                                <input disabled type="text" class="form-options__quantity" :value="item.quantity">
                            </div>
                        </div>
                        <!--<div class="form-options rigging">
                            <p>Оснастки</p>
                            <p>кол-во</p>
                            <div class="form-options__item">
                                <input disabled type="text" class="form-options__rigging" value="A.P OM-5992-V">
                                <input disabled type="text" class="form-options__quantity" value="2 шт">
                            </div>
                            <div class="form-options__item">
                                <input disabled type="text" class="form-options__color" value="A.P OM-5992-V">
                                <input disabled type="text" class="form-options__quantity" value="2 шт">
                            </div>
                        </div>-->
                        <div class="button-block">
                            <button v-on:click.prevent="modalShow = false" class="close">
                                Отмена
                            </button>
                            <input type="submit" v-if="(items.length > 0)" v-on:click.prevent="addToBasket" class="send-form" value="ок">
                        </div>
                    </form>
                </div>
            </div>
        </div>
    </b-modal>
</template>
<script>
export default {
    props: [
        "product",
        "basket",
        "count"
    ],
    data: () => ({
        modalShow: false,
        productInfo: {},
        collectionId: 0,
        productId: 0,
        basketItem: [],
        items: []
    }),
    methods: {
        /**
         * отформатированные значения на основании корзины и данных по SKU
         */
        getBasketItems(){
            let res = [];

            if(this.productInfo.hasOwnProperty('offers')){
                for(let i = 0; i <= Object.keys(this.productInfo.offers).length; i++){
                    let offer = this.productInfo.offers[Object.keys(this.productInfo.offers)[i]];

                    if(typeof offer != "undefined"){
                        for(let j = 0; j <= this.basketItem.length; j++){
                            if(this.basketItem.length > 0){
                                let quantityItem = this.basketItem[j];

                                if(typeof quantityItem != "undefined"){
                                    if(parseInt(quantityItem.offerId) === parseInt(offer.id)){
                                        res.push({
                                            'collectionId': this.collectionId,
                                            'productId': this.productInfo.id,
                                            'productName': this.productInfo.name,
                                            'offerId': offer.id,
                                            'offerName': offer.name,
                                            'colorTitle': offer.prop.color.title,
                                            'quantity': quantityItem.value
                                        });
                                    }
                                }
                            }
                        }
                    }
                }
            }

            this.items = res;
        },

        /**
         * Добавление в корзину
         */
        addToBasket(){
            this.$store.dispatch('ADD_TO_BASKET', this.items);

            this.modalShow = false;

            this.$parent.$emit('clearBasket');
        }
    },
    watch: {
        product: function(newData, oldData) {
            this.productId = newData;
            this.productInfo = this.$store.state.productInfo;
        },
        basket: function(newData, oldData) {
            this.basketItem = newData;

            this.getBasketItems();
        },
        count: function(newData, oldData) {
            this.getBasketItems();
        },
    },
    created() {
        this.productId = this.$store.state.productID;
        this.productInfo = this.$store.state.productInfo;
        this.collectionId = this.$route.params.collection;
    }
}
</script>
