<template>
    <main>
        <div class="container">
            <div class="main-wrapper product-card">
                <catalogElement :product="productId"></catalogElement>
                <div class="order-block">
                    <h2 class="grey-title">Бланк заказа</h2>
                    <div class="order-form">
                        <catalogElementOffers :product="productId"></catalogElementOffers>
                        <catalogElementBasket :product="productId"></catalogElementBasket>
                    </div>
                </div>
                <div class="product-footer">
                    <catalogElementNavigation :product="productId"></catalogElementNavigation>
                </div>
            </div>
        </div>
        <ModalOrder :product="productId" :basket="basketItem" :count="countBasketItem"></ModalOrder>
        <ModalPassport :product="productId"></ModalPassport>
        <ModalSlider :product="productId"></ModalSlider>
    </main>
</template>
<script>
import ModalOrder from "@/components/modals/ModalOrder"
import ModalPassport from "@/components/modals/ModalPassport"
import ModalSlider from "@/components/modals/ModalSlider"
import CatalogElementNavigation from "@/components/catalog/element/navigation"
import CatalogElementOffers from "@/components/catalog/element/offers"
import CatalogElementBasket from "@/components/catalog/element/basket"
import CatalogElement from "@/components/catalog/element/detail"
export default {
    data: () => ({
        productId: 0,
        basketItem: [], 
        info: []
    }),
    components: {
        ModalOrder, ModalPassport, ModalSlider,
        CatalogElementNavigation, CatalogElementOffers, 
        CatalogElementBasket, CatalogElement
    },
    methods: {
        
        
    },
    beforeCreate(){
        let self = this;
        if(this.$store.state.username == null){
            this.$store.dispatch('GET_USER_INFO')
        }
        if(this.$store.state.products.length == 0){
            this.$store.dispatch('GET_PRODUCT_LIST', this.$route.params.collection)
            .then(response => {
                self.$store.dispatch('SET_PRODUCT', self.$route.params.element);
                self.productId = self.$store.state.productID;
            })
            .catch(err => console.log(err));;
        }
        else{
            this.$store.dispatch('SET_PRODUCT', this.$route.params.element);
            this.productId = this.$store.state.productID;
        }
    },
    computed: {
        countBasketItem: function(){
            let result = 0;

            if(Object.keys(this.basketItem).length > 0){
                for(let i = 0; i <= this.basketItem.length; i++){
                    if(typeof this.basketItem[i] != "undefined"){
                        result += this.basketItem[i].value;
                    }
                }
            }

            return result;
        }
    },
    mounted(){
        let self = this;
        this.$on('changeProductId', function (id) {
            self.productId = id;
            self.basketItem = [];
        });

        // добалевление товара в корзину
        this.$on('addBasket', function (responce) {
            self.basketItem = responce;
        });

        /**
         * Очистить временную корзину, после добавления в localStorage и state 
         */
        this.$on('clearBasket', function () {
            //self.basketItem = [];
        });
    }
}
</script>