<template>
    <div class="product-info">
        <b-link v-b-modal.modalSlider v-if="countMorePhoto" class="product-info__img" v-bind:style="{ backgroundImage: 'url(' + info.previewPicture + ')' }">
            <p class="number">{{countMorePhoto}}</p>
        </b-link>
        <div v-if="!countMorePhoto" class="product-info__img" v-bind:style="{ backgroundImage: 'url(' + info.previewPicture + ')' }"></div>
        <div class="product-info__list">
            <h1 class="product-info__title">{{info.name}}</h1>
            <b-link v-b-modal.modalPassport class="product-info__link" :info="info">
                паспорт модели
            </b-link>
            <div class="product-options" v-if="countTypeMount">
                <div class="option">
                    <p class="option__title">Крепление:</p>
                    <p class="option__text" v-for="(item, index) in info.prop.typeOfMount" :key="index">{{item}}</p>
                </div>
            </div>
            <div class="product-info__price">
                <span>от </span>
                <span class="num">{{price}}</span>
                <span> грн./шт.</span>
            </div>
        </div>
    </div>
</template>
<script>
export default {
    name: 'catalogElement',
    props: [
        "product"
    ],
    data: function(){
        return {
            collectionId: 0,
            productId: 0,
            info: []
        }
    },
    methods: {

    },
    computed: {
        price: function(){
            let res = 0;
            if(typeof this.info.price != "undefined"){
                res = this.info.price.value;
            }
            return res;
        },
        countMorePhoto(){
            if(typeof this.info.photo != "undefined"){
                return Object.keys(this.info.photo).length;
            }
            else{
                return false;
            }
        },
        countTypeMount(){
            if(typeof this.info.prop != "undefined"){
                return Object.keys(this.info.prop.typeOfMount).length;
            }
            else{
                return false;
            }
        },
    },
    watch: {
        product: function(newVal, oldVal) {
            this.productId = newVal;
            this.info = this.$store.state.productInfo;
        },
        info: function(){
            // this.$emit('productPhoto', this.info);
            this.$emit('productInfo', this.info);
        }
    },
    created() {
        this.productId = this.$store.state.productID;
        this.collectionId = this.$route.params.collection;
        this.info = this.$store.state.productInfo;
        
    }
}
</script>