<template>
    <b-modal v-model="modalShow"  id="modalPassport" hide-footer>
        <div class="modal-dialog" role="document">
            <div class="modal-content">
                <div class="modal-body modalPassport">
                    <section class="passport-info">
                        <h1 class="passport-info__title">паспорт модели</h1>
                        <h2 class="passport-info__subtitle">{{info.name}}</h2>
                        <h3 class="grey-title" v-if="countPlaceOfApplication">Место применения</h3>
                        <div class="passport-info__options-block" v-if="countPlaceOfApplication">
                            <div class="passport-info__option">
                                <p 
                                    v-for="(item, index) in passportInfo.placeOfApplication" :key="index">
                                    {{item}}
                                </p>
                            </div>
                        </div>
                        <h3 class="grey-title" v-if="passportInfo.trustPoint">Точка доверия</h3>
                        <div class="passport-info__options-block" v-if="passportInfo.trustPoint">
                            <p class="passport-info__option" v-html="passportInfo.trustPoint"></p>
                        </div>
                        <h3 class="grey-title" v-if="countPhotoHistory">Фото аналога / история</h3>
                        <div class="passport-info__options-block" v-if="countPhotoHistory">
                            <slick 
                                class="history-slider"
                                :options="sliderOptions">
                                <div 
                                    class="history-slider__item"
                                    v-for="(item, index) in passportInfo.photoHistory" :key="index">
                                    <a href="" v-on:click.prevent="stopEvent($event)" :style="{ backgroundImage: 'url('+ item +')' }"></a>
                                </div>
                            </slick>
                        </div>
                        <h3 class="grey-title" v-if="countTypeMount">Тип крепления</h3>
                        <div class="passport-info__options-block" v-if="countTypeMount">
                            <p 
                                class="passport-info__option"
                                v-for="(item, index) in passportInfo.typeOfMount" :key="index">
                                 - {{item}}
                            </p>
                        </div>
                        <h3 class="grey-title" v-if="countRecommendation">К этому товару подходят</h3>
                        <div class="passport-info__options-block recomended-block" v-if="countRecommendation">
                            <div class="chess">
                                <a href="" v-on:click.prevent="stopEvent($event)" class="chess__item" v-for="(item, index) in passportInfo.recommendations" :key="index">
                                    <span class="chess__num">{{index + 1}}</span>
                                    <div 
                                        class="chess__img" 
                                        :style="{ backgroundImage: 'url('+ item.picture +')' }"></div>
                                    <p class="chess__discription">
                                        {{item.name}}
                                    </p>
                                </a>
                            </div>
                        </div>
                    </section>
                </div>
            </div>
        </div>
    </b-modal>
</template>
<script>
import Slick from 'vue-slick';
export default {
    components: { Slick },
    props: [
        "product"
    ],
    data: () => ({
        modalShow: false,
        sliderOptions: {
            slidesToShow: 2,
            slidesToScroll: 1,
            arrows: false,
            dots: false,
            centerMode: true,
            infinite: false,
            variableWidth: true
        },
        info: {},
        productId: 0,
        passportInfo: {}  //я не знаю почему, но если общатьсь напрямую с info, данные выводятся, но в консоли куча ошибок
    }),
    methods: {
        stopEvent(e){
            e.stopPropagation();
        }
    },
    computed: {
        countPhotoHistory(){
            if(typeof this.passportInfo.photoHistory != "undefined"){
                return Object.keys(this.passportInfo.photoHistory).length;
            }
            else{
                return false;
            }
        },
        countRecommendation(){
            if(typeof this.passportInfo.recommendations != "undefined"){
                return Object.keys(this.passportInfo.recommendations).length;
            }
            else{
                return false;
            }
        },
        countPlaceOfApplication(){
            if(typeof this.passportInfo.placeOfApplication != "undefined"){
                return Object.keys(this.passportInfo.placeOfApplication).length;
            }
            else{
                return false;
            }
        },
        countTypeMount(){
            if(typeof this.passportInfo.typeOfMount != "undefined"){
                return Object.keys(this.passportInfo.typeOfMount).length;
            }
            else{
                return false;
            }
        },
    },
    watch: {
        product: function(newData, oldData) {
            this.productId = newData;
            this.info = this.$store.state.productInfo;
        },
        info: function(){
            this.passportInfo = this.info.prop
        }
    },
    beforeCreate() {
        this.productId = this.$store.state.productID;
        this.collectionId = this.$route.params.collection;
        this.info = this.$store.state.productInfo;
    }
}
</script>
<style lang="scss" scoped>
.modal-content{
    max-height: 90vh ;
    border: none;
}
.passport-info__options-block{
    padding-left: 10px;
    padding-right: 10px;
}
.chess{
    width: 100%;
}
.chess__num{
    display: flex;
}
</style>