<template>
<div>
    <div class="size-block" v-if="isSize">
        <p class="size-block__title">Размер <span>(mm):</span></p>
        <div class="size-block__items">
            <span v-for="(sizeItem, sizeIndex) in sizeList" :key="sizeIndex" :class="{active:sizeActive(sizeItem.value)}" v-bind:data-value="sizeItem.value" @click="setSize(sizeItem.value)">{{sizeItem.title}}</span>
        </div>
    </div>
    <div class="size-block" v-if="isOrientation">
        <p class="size-block__title">Ориентация <span>:</span></p>
        <div class="size-block__items">
            <span v-for="(orientationItem, orientationIndex) in orientationList" :key="orientationIndex" :class="{active:orientationActive(orientationItem.value)}" v-bind:data-value="orientationItem.value" @click="setOrientation(orientationItem.value)">{{orientationItem.title}}</span>
        </div>
    </div>
    <div class="options-title" v-if="isColor">
        <div class="options-title__left">
            <p class="color-title">цвет</p>
            <p class="quantity-title">кол-во</p>
        </div>
    </div>
    <div class="options-list">
        <div class="color" v-if="isColor">
            <div class="options-list__item" v-for="(colorItem, colorIndex) in colorList" :key="colorIndex">
                <p class="color-hex" v-bind:style="{ backgroundColor: colorItem.hex }"></p>
                <span>{{colorItem.title}}</span>
                <div class="input-block">
                    <span class="minus" @click="minus(colorItem.value)"></span>
                    <input type="number" min="0" @input="setQuantity($event.target.value, colorItem.value)" v-bind:value="getQuantity(colorItem.value)">
                    <span class="plus" @click="plus(colorItem.value)"></span>
                </div>
            </div>
        </div>
    </div>
</div>
</template>
<script>
export default {
    props: [
        "product"
    ],
    name: 'catalogElementOffers',
    data: function(){
        return {
            collectionId: 0,
            productId: 0,
            info: [],
            quantity: [],
            currentSize: 0,
            currentOrientation: 0,
            sizeList: {},
            orientationList: {},
            colorList: {}
        }
    },
    methods: {
        getQuantity(val){
            let i = 0;

            // определить offerId по значению свойств (размер, цвет, ориентация)
            let id = this.getOfferId(val);

            $.each(this.quantity, function (key, item) {
                if (item.offerId == id) {
                    i = item.value;
                }
            });
            
            return i
        },
        setQuantity(res, val){
            let set = false;

            // определить offerId по значению свойств (размер, цвет, ориентация)
            let id = this.getOfferId(val);

            for (let i in this.quantity) {
                if (typeof this.quantity[i] != 'undefined') {
                    if (this.quantity[i].offerId == id) {
                        set = true;
                        this.quantity[i].value = parseInt(res | 0);
                    }
                }
            }
            
            if (!set) {
                this.quantity.push({
                    'offerId': id,
                    'type': 'sku',
                    'value': parseInt(res)
                });
            }
        },
        plus(val){
            let set = false;

            // определить offerId по значению свойств (размер, цвет, ориентация)
            let id = this.getOfferId(val);

            for (let i in this.quantity) {
                if (typeof this.quantity[i] != 'undefined') {
                    if (this.quantity[i].offerId == id) {
                        set = true;
                        this.quantity[i].value++;
                    }
                }
            }

            if (!set) {
                this.quantity.push({
                    'offerId': id,
                    'type': 'sku',
                    'value': 1
                });
            }
        },
        minus(val){
            let set = false;

            // определить offerId по значению свойств (размер, цвет, ориентация)
            let id = this.getOfferId(val);

            for (let i in this.quantity) {
                if (typeof this.quantity[i] != 'undefined') {
                    if (this.quantity[i].offerId == id) {
                        set = true;
                        if(parseInt(this.quantity[i].value) > 0){
                            this.quantity[i].value--;
                        }
                        else{
                            this.quantity[i].value = 0;
                        }
                    }
                }
            }

            if (!set) {
                this.quantity.push({
                    'offerId': id,
                    'type': 'sku',
                    'value': 0
                });
            }
        },
        /**
         * размерная сетка
         */
        getSizeList(){
            let arr = [];
            
            if(this.info.hasOwnProperty('offers')){
                arr = this.info.formated.sizeList;
            }

            this.sizeList = arr;
        },
        getOrientationList(){
            let arr = [];
            
            if(this.info.hasOwnProperty('offers')){
                arr = this.info.formated.orientationList;
            }

            this.orientationList = arr;
        },
        /**
         * активность элемента размерной сетки
         */
        sizeActive(val){
            if(this.currentSize == val) return true; else return false;
        },
        orientationActive(val){
            if(this.currentOrientation == val) return true; else return false;
        },
        setSize(sizeValue){
            this.currentSize = sizeValue;
            this.getColorList();
            this.quantity = [];
        },
        setOrientation(orientationValue){
            this.currentOrientation = orientationValue;
            this.getColorList();
            this.quantity = [];
        },
        getColorList(){
            let arr = [];
            
            if(this.info.hasOwnProperty('offers')){
                for(let i = 0; i <= Object.keys(this.info.offers).length; i++){
                    let offer = this.info.offers[Object.keys(this.info.offers)[i]];

                    if(typeof offer != "undefined"){
                        if((parseInt(this.currentSize) > 0) && (parseInt(this.currentOrientation) > 0)){
                            if(
                                (parseInt(offer.prop.size.value) === parseInt(this.currentSize)) && 
                                (parseInt(offer.prop.orientation.value) === parseInt(this.currentOrientation))
                            ){
                                arr.push(offer.prop.color);
                            }
                        }
                        else if(parseInt(this.currentOrientation) > 0){
                            if(parseInt(offer.prop.orientation.value) === parseInt(this.currentOrientation)){
                                arr.push(offer.prop.color);
                            }
                        }
                        else if(parseInt(this.currentSize) > 0){
                            if(parseInt(offer.prop.size.value) === parseInt(this.currentSize)){
                                arr.push(offer.prop.color);
                            }
                        }
                        else{
                            arr.push(offer.prop.color);
                        }
                    }
                }
            }

            this.colorList = arr;
        },

        /**
         * Определить ID SKU по свойствам (размер, цвет и ориентация)
         */
        getOfferId(colorValue){
            let id = 0;

            if(this.info.hasOwnProperty('offers')){
                for(let i = 0; i <= Object.keys(this.info.offers).length; i++){
                    let offer = this.info.offers[Object.keys(this.info.offers)[i]];

                    if(typeof offer != "undefined"){
                        if(parseInt(this.currentSize) > 0){
                            if(
                                (parseInt(offer.prop.size.value) === parseInt(this.currentSize)) && 
                                (parseInt(offer.prop.color.value) === parseInt(colorValue))
                            ){
                                id = offer.id;
                            }
                        }
                        else{
                            if(parseInt(offer.prop.color.value) === parseInt(colorValue)){
                                id = offer.id;
                            }
                        }
                    }
                }
            }

            return id;
        },
        init(){
            this.getSizeList();
            this.getOrientationList();

            // установка первого размера как текущего
            if(Object.keys(this.sizeList).length > 0){
                this.setSize(Object.keys(this.sizeList)[0]);
            }
            if(Object.keys(this.orientationList).length > 0){
                this.setOrientation(Object.keys(this.orientationList)[0]);
            }

            this.getColorList();
        }
    },
    computed: {
        isSize: function(){
            if(Object.keys(this.sizeList).length > 0) return true; else return false;
        },
        isColor: function(){
            if(Object.keys(this.colorList).length > 0) return true; else return false;
        },
        isOrientation: function(){
            if(Object.keys(this.orientationList).length > 0) return true; else return false;
        }
    },
    watch: {
        product: function(newId, oldId) {
            this.productId = newId;
            this.info = this.$store.state.productInfo;
            this.currentSize = 0;
            this.currentOrientation = 0;
            this.quantity = [];

            this.init();
        },
        quantity: function(){
            this.$parent.$emit('addBasket', this.quantity);
        }
    },
    created() {
        this.productId = this.$store.state.productID;
        this.collectionId = this.$route.params.collection;
        this.info = this.$store.state.productInfo;
        this.quantity = [];

        this.init();
    },
}
</script>