<template>
    <div class="pagination">
        <a class="prew" @click="prev()">предыдущая</a>
        <p class="page-num">{{number}}</p>
        <a class="next" @click="next()">следующая</a>
    </div>
</template>
<script>
export default {
    name: 'catalogElementNavigation',
    props: [
        "product"
    ],
    data: function(){
        return {
            collectionId: 0,
            productId: 0,
            items: [],
            key: 0
        }
    },
    methods: {
        prev(){
            let self = this;
            let id = this.productId;
            let currentKey = this.currentKey(); // текущий ключ
            let isPush = true;

            // следующий элемент currentKey+1
            // првоерим существование такого элемента в списке
            if(parseInt(currentKey) !== 0){
                id = this.items[(currentKey-1)].id;
            }
            else{
                isPush = false;
            }

            if(isPush){
                this.$store.dispatch('SET_PRODUCT', id);
                this.$parent.$emit('changeProductId', id);
                this.$router.push('/catalog/'+this.collectionId+'/'+id).catch(err => {});
            }
        },
        next(){
            let self = this;
            let id = this.productId;
            let currentKey = this.currentKey(); // текущий ключ
            let isPush = true;

            // следующий элемент currentKey+1
            // првоерим существование такого элемента в списке
            if(parseInt(currentKey) !== (parseInt(this.items.length)-1)){
                if(this.items[(currentKey+1)]){
                    id = this.items[(currentKey+1)].id;
                }
            }
            else{
                isPush = false;
            }

            if(isPush){
                if(this.$store.getters.GET_RATING_INFO){ //Проверка выставлена ли оценка
                    this.$store.dispatch('SET_PRODUCT', id);
                    this.$parent.$emit('changeProductId', id);
                    this.$router.push('/catalog/'+this.collectionId+'/'+id).catch(err => {});
                    this.$store.dispatch('UNSET_RATING') //Изменить 'addedRating' на false для следующей проверки
                }else{
                    this.makeToast();
                    this.scrollToElement();
                    
                }
            }
        },
        makeToast(append = false) {
            this.$bvToast.toast('Вы забыли поставить оценку', {
                title: 'Ошибка!',
                autoHideDelay: 3000,
                variant: 'danger',
                toaster: 'b-toaster-top-center',
                appendToast: append
            })
        },
        currentKey(){
            let res = 0;
            let self = this;
            for (let i = 0; i < this.items.length; i++) {
                let item = this.items[i];
                if(parseInt(item.id) === parseInt(self.productId)){
                    res = i;
                }
            }

            return res;
        },
        scrollToElement() {
            let smileBlock = document.querySelector('.smile-block');
            let orderBlock = document.querySelector('.order-block');
            function getCoords() { 
                var smile = smileBlock.getBoundingClientRect();
                return smile.top + pageYOffset;
            }
            let smileBlockCoords = getCoords()
            orderBlock.scrollTo({
                top: smileBlockCoords,
                behavior: 'smooth'
            });
        }
    },
    watch: {
        product: function(newVal, oldVal) {
          this.productId = newVal;
          this.items = this.$store.state.products;
        },
    },
    
    computed: {
        number: function(){
            return this.currentKey();
        }
    },
    created() {
        this.productId = this.$store.state.productID;
        this.collectionId = this.$route.params.collection;
        this.items = this.$store.state.products;
    }
}
</script>