<template>
<div>
    <b-button v-b-modal.modalOrder id="addToOrder">
        заказать образцы
    </b-button>
    <p class="grey-title">Оценка клиента</p>
    <textarea class="comment" v-model="comment" placeholder="Комментарий"></textarea>
    <div class="smile-block">
        <p data-rating="veryBad" v-on:click="setRating($event)" v-bind:class="{active: activeLink === 'veryBad'}">
            <img class="colored" src="@/img/smile5.1.svg" alt="">
            <img src="@/img/smile5.0.svg" alt="">
        </p>
        <p data-rating="bad" v-on:click="setRating($event)" v-bind:class="{active: activeLink === 'bad'}">
            <img class="colored" src="@/img/smile4.1.svg" alt="">
            <img src="@/img/smile4.0.svg" alt="">
        </p>
        <p data-rating="normal" v-on:click="setRating($event)" v-bind:class="{active: activeLink === 'normal'}">
            <img class="colored" src="@/img/smile3.1.svg" alt="">
            <img src="@/img/smile3.0.svg" alt="">
        </p>
        <p data-rating="good" v-on:click="setRating($event)" v-bind:class="{active: activeLink === 'good'}">
            <img class="colored" src="@/img/smile2.1.svg" alt="">
            <img src="@/img/smile2.0.svg" alt="">
        </p>
        <p data-rating="veryGood" v-on:click="setRating($event)"  v-bind:class="{active: activeLink === 'veryGood'}">
            <img class="colored" src="@/img/smile1.1.svg" alt="">
            <img src="@/img/smile1.0.svg" alt="">
        </p>
    </div>
</div>
</template>
<script>
export default {
    name: 'catalogElementBasket',
    props: ['product'],
    data: function(){
        return {
            collectionId: 0,
            productId: 0,
            activeLink: '',
            comment: ''
        }
    },
    methods: {
        setRating(e){
            this.$store.dispatch('SET_RATING')
            let dataRating = e.target.parentNode.getAttribute('data-rating');
            this.activeLink = dataRating
            let that = this;

            let productInfo = {
                "productId": this.product,
                "rating": this.activeLink,
                "comment": this.comment
            }
            
            if(localStorage.getItem("productRating") == null){  //Добавить отзыв в localStorage если его еще там нет
                let productRating = []
                productRating.push(productInfo)
                productRating = JSON.stringify(productRating);
                localStorage.setItem("productRating", productRating);
            }else{
                let productRating = localStorage.getItem("productRating");
                productRating = JSON.parse(productRating);
                
                productRating.forEach(function(el, i){          //Если решили обновить оценку
                    if(el.productId == that.product){
                        productRating.splice(i, 1);             //Удаляем старую
                    }
                })
                
                productRating.push(productInfo)                 //Добавляем новую
                productRating = JSON.stringify(productRating);
                localStorage.setItem("productRating", productRating);
            }
        
            // localStorage.removeItem('productRating');  
                
        }
    },
    mounted() {
        this.productId = this.$route.params.element;
        this.collectionId = this.$route.params.collection;
    },
    watch: {
        product: function(){
            this.activeLink = ''
            this.comment = ''
            let that = this
            if(localStorage.getItem("productRating") != null){
                let productRating = localStorage.getItem("productRating");
                    productRating = JSON.parse(productRating);  
                    productRating.forEach(function(el, i){     
                        if(el.productId == that.product){
                            that.comment = el.comment
                        }
                    })
            }
        }
    }
}
</script>